-            Expr::Subquery(sql) => format!("({})", sql),
+
+            Expr::Subquery(sql) => format!("({sql})"),
+
             Expr::Raw(sql) => sql.clone(),
+
             Expr::Paren(expr) => {
-                let expr_sql = expr.build(params, offset);
-                format!("({})", expr_sql)
+                let expr_sql = expr.build_with_dialect(dialect, params, offset);
+                format!("({expr_sql})")
             }
+
+            Expr::CountStar => "COUNT(*)".to_string(),
+        }
+    }
