+// ==================== CASE Builder ====================
+
+/// Builder for CASE WHEN expressions.
+#[derive(Debug, Clone)]
+pub struct CaseBuilder {
+    when_clauses: Vec<(Expr, Expr)>,
+}
+
+impl CaseBuilder {
+    /// Add a WHEN condition with its THEN result.
+    pub fn when(mut self, condition: impl Into<Expr>, result: impl Into<Expr>) -> Self {
+        self.when_clauses.push((condition.into(), result.into()));
+        self
+    }
+
+    /// Finalize with an ELSE clause (optional).
+    pub fn otherwise(self, else_result: impl Into<Expr>) -> Expr {
+        Expr::Case {
+            when_clauses: self.when_clauses,
+            else_clause: Some(Box::new(else_result.into())),
+        }
+    }
+
+    /// Finalize without an ELSE clause.
+    pub fn end(self) -> Expr {
+        Expr::Case {
+            when_clauses: self.when_clauses,
+            else_clause: None,
         }
     }
 }

+// ==================== Order Expression ====================
+
+/// Sort direction for ORDER BY.
+#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
+pub enum OrderDirection {
+    /// Ascending order (default)
+    #[default]
+    Asc,
+    /// Descending order
+    Desc,
+}
+
+/// NULLS FIRST/LAST specification.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub enum NullsOrder {
+    /// NULLS FIRST
+    First,
+    /// NULLS LAST
+    Last,
+}
+
+/// An expression with ordering information for ORDER BY.
+#[derive(Debug, Clone)]
+pub struct OrderExpr {
+    /// The expression to order by
+    pub expr: Expr,
+    /// Sort direction
+    pub direction: OrderDirection,
+    /// NULLS FIRST/LAST
+    pub nulls: Option<NullsOrder>,
+}
+
+impl OrderExpr {
+    /// Set NULLS FIRST.
+    pub fn nulls_first(mut self) -> Self {
+        self.nulls = Some(NullsOrder::First);
+        self
+    }
+
+    /// Set NULLS LAST.
+    pub fn nulls_last(mut self) -> Self {
+        self.nulls = Some(NullsOrder::Last);
+        self
+    }
+
+    /// Build SQL for this ORDER BY expression.
+    pub fn build(&self, dialect: Dialect, params: &mut Vec<Value>, offset: usize) -> String {
+        let mut sql = self.expr.build_with_dialect(dialect, params, offset);
+
+        sql.push_str(match self.direction {
+            OrderDirection::Asc => " ASC",
+            OrderDirection::Desc => " DESC",
+        });
+
+        if let Some(nulls) = self.nulls {
+            sql.push_str(match nulls {
+                NullsOrder::First => " NULLS FIRST",
+                NullsOrder::Last => " NULLS LAST",
+            });
+        }
+
+        sql
+    }
+}
